/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Phone number validation (E.164 format)
 * - Recipient resolution (user ID -> phone number mapping)
 * - Message truncation with configurable max length (SMS character limits)
 * - Priority-aware delivery metadata
 * - Configurable sender ID / phone number
 *
 * Recipient Resolution:
 * The adapter can resolve non-phone identifiers (e.g., user IDs) to phone
 * numbers via a mapping registered with registerRecipient(). If no mapping
 * exists, the recipient is used as-is and must be a valid phone number.
 *
 * Message Formatting:
 * SMS messages are composed from the notification subject and body.
 * Messages exceeding maxMessageLength are truncated with an ellipsis.
 *
 * Implements: NotificationAdapter (channel: 'sms')
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the SMS adapter.
 */
export interface SmsAdapterConfig {
  /** Sender ID or phone number (the "from" number) */
  fromNumber: string;
  /** Whether the adapter is enabled. When false, isAvailable() returns false. */
  enabled: boolean;
  /** Maximum SMS message length in characters. Default: 160 (standard SMS limit). */
  maxMessageLength: number;
}

/** Default SMS adapter configuration. */
export const defaultSmsConfig: SmsAdapterConfig = {
  fromNumber: '+15550000000',
  enabled: true,
  maxMessageLength: 160,
};

/**
 * Represents a composed SMS message ready for delivery.
 * Used internally by the adapter to structure outgoing messages.
 */
export interface SmsMessage {
  /** Sender phone number / ID */
  from: string;
  /** Recipient phone number */
  to: string;
  /** Message body (subject + body combined, possibly truncated) */
  body: string;
  /** Notification priority level */
  priority: string;
  /** Timestamp of when the message was sent */
  timestamp: Date;
}

/**
 * E.164 phone number validation pattern.
 * Matches numbers like +14155551234 (+ followed by 7-15 digits).
 */
const PHONE_REGEX = /^\+[1-9]\d{6,14}$/;

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private config: SmsAdapterConfig;
  private sentMessages: SmsMessage[] = [];
  private recipientMap: Map<string, string> = new Map();

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = { ...defaultSmsConfig, ...config };
  }

  // ---------------------------------------------------------------------------
  // NotificationAdapter Interface
  // ---------------------------------------------------------------------------

  /**
   * Send an SMS notification.
   *
   * Processing pipeline:
   * 1. Check adapter availability.
   * 2. Resolve recipient (map user IDs to phone numbers if registered).
   * 3. Validate the resolved phone number.
   * 4. Compose the SMS message (subject + body, truncated if needed).
   * 5. Deliver (currently in-memory; replace with SMS gateway for production).
   * 6. Return delivery result.
   *
   * @param payload - The notification to deliver via SMS.
   * @returns Result indicating delivery success or failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.isAvailable()) {
      return {
        success: false,
        errorMessage: 'SMS adapter is not available (disabled in configuration)',
      };
    }

    try {
      // Step 1: Resolve recipient (user ID -> phone number, or passthrough)
      const resolvedRecipient = this.resolveRecipient(payload.recipient);

      // Step 2: Validate the resolved phone number
      if (!this.validatePhoneNumber(resolvedRecipient)) {
        this.logger.warn(`Invalid recipient phone number: ${resolvedRecipient}`);
        return {
          success: false,
          errorMessage: `Invalid recipient phone number: ${resolvedRecipient}`,
        };
      }

      // Step 3: Compose the SMS message
      const message = this.composeMessage(payload, resolvedRecipient);

      // Step 4: Deliver (in-memory store; replace with real SMS gateway in production)
      this.logger.info(
        `SMS sent: to=${message.to}, from=${message.from}, length=${message.body.length}`,
      );
      this.sentMessages.push(message);

      return {
        success: true,
        adapterResponse: {
          messageId: `sms-${Date.now()}`,
          from: message.from,
          to: message.to,
        },
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown SMS delivery error';
      this.logger.error(`SMS delivery failed: ${errorMessage}`);
      return {
        success: false,
        errorMessage,
      };
    }
  }

  /**
   * Check if the SMS adapter is available for sending.
   */
  isAvailable(): boolean {
    return this.config.enabled;
  }

  // ---------------------------------------------------------------------------
  // Recipient Resolution
  // ---------------------------------------------------------------------------

  /**
   * Register a mapping from a non-phone identifier to a phone number.
   * This allows the adapter to resolve user IDs, usernames, etc. to
   * deliverable phone numbers.
   *
   * @param identifier - The non-phone identifier (e.g., user ID).
   * @param phoneNumber - The phone number to map it to (E.164 format).
   */
  registerRecipient(identifier: string, phoneNumber: string): void {
    this.recipientMap.set(identifier, phoneNumber);
  }

  /**
   * Resolve a recipient identifier to a phone number.
   * If a mapping is registered for the identifier, returns the mapped phone number.
   * Otherwise returns the recipient as-is (trimmed).
   *
   * @param recipient - The recipient identifier or phone number.
   * @returns The resolved phone number.
   */
  resolveRecipient(recipient: string): string {
    const mapped = this.recipientMap.get(recipient);
    if (mapped) {
      return mapped;
    }
    return recipient.trim();
  }

  /**
   * Validate that a string is a well-formed E.164 phone number.
   *
   * @param phoneNumber - The string to validate.
   * @returns true if the string is a valid E.164 phone number.
   */
  validatePhoneNumber(phoneNumber: string): boolean {
    return PHONE_REGEX.test(phoneNumber);
  }

  // ---------------------------------------------------------------------------
  // Test Helpers
  // ---------------------------------------------------------------------------

  /**
   * Get all SMS messages sent by this adapter (useful for testing).
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear the sent messages log (useful for testing).
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<SmsAdapterConfig> {
    return { ...this.config };
  }

  // ---------------------------------------------------------------------------
  // Private Methods
  // ---------------------------------------------------------------------------

  /**
   * Compose an SmsMessage from a NotificationPayload.
   * Combines subject and body into a single SMS message, truncating
   * if it exceeds the configured maxMessageLength.
   *
   * @param payload - The notification payload.
   * @param resolvedRecipient - The resolved phone number.
   * @returns The composed SMS message.
   */
  private composeMessage(payload: NotificationPayload, resolvedRecipient: string): SmsMessage {
    // Combine subject and body into a single SMS message
    const fullMessage = `${payload.subject}: ${payload.body}`;
    const body = this.truncateMessage(fullMessage);

    return {
      from: this.config.fromNumber,
      to: resolvedRecipient,
      body,
      priority: payload.priority,
      timestamp: new Date(),
    };
  }

  /**
   * Truncate a message to the configured maxMessageLength.
   * If the message exceeds the limit, it is cut and an ellipsis is appended.
   *
   * @param message - The full message text.
   * @returns The truncated message (or original if within limits).
   */
  private truncateMessage(message: string): string {
    if (message.length <= this.config.maxMessageLength) {
      return message;
    }
    return message.substring(0, this.config.maxMessageLength - 3) + '...';
  }
}

