import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('channel', () => {
    it('should report sms as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('isAvailable', () => {
    it('should be available by default', () => {
      expect(adapter.isAvailable()).toBe(true);
    });

    it('should be unavailable when disabled', () => {
      const disabled = new SmsAdapter({ enabled: false });
      expect(disabled.isAvailable()).toBe(false);
    });
  });

  describe('send', () => {
    const payload: NotificationPayload = {
      recipient: '+14155551234',
      subject: 'Test Subject',
      body: 'Test body content',
      channel: 'sms',
      priority: 'normal',
    };

    it('should send an SMS successfully', async () => {
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.to).toBe('+14155551234');
    });

    it('should record sent messages', async () => {
      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+14155551234');
      expect(sent[0]?.body).toContain('Test Subject');
      expect(sent[0]?.body).toContain('Test body content');
    });

    it('should compose from number from config', async () => {
      const custom = new SmsAdapter({
        fromNumber: '+18005551234',
      });

      await custom.send(payload);

      const sent = custom.getSentMessages();
      expect(sent[0]?.from).toBe('+18005551234');
    });

    it('should use default from number', async () => {
      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.from).toBe('+15550000000');
    });

    it('should fail when adapter is disabled', async () => {
      const disabled = new SmsAdapter({ enabled: false });
      const result = await disabled.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('not available');
    });

    it('should combine subject and body into SMS message', async () => {
      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body).toBe('Test Subject: Test body content');
    });

    it('should include messageId in adapter response', async () => {
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.messageId).toBeDefined();
      expect(result.adapterResponse?.messageId).toMatch(/^sms-/);
    });
  });

  // =========================================================================
  // Message Truncation Tests
  // =========================================================================

  describe('message truncation', () => {
    it('should not truncate messages within the limit', async () => {
      const shortPayload: NotificationPayload = {
        recipient: '+14155551234',
        subject: 'Hi',
        body: 'Short message',
        channel: 'sms',
        priority: 'normal',
      };

      await adapter.send(shortPayload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body).toBe('Hi: Short message');
    });

    it('should truncate messages exceeding default 160 character limit', async () => {
      const longBody = 'A'.repeat(200);
      const longPayload: NotificationPayload = {
        recipient: '+14155551234',
        subject: 'Alert',
        body: longBody,
        channel: 'sms',
        priority: 'normal',
      };

      await adapter.send(longPayload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body.length).toBe(160);
      expect(sent[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should respect custom maxMessageLength', async () => {
      const custom = new SmsAdapter({ maxMessageLength: 50 });

      const longPayload: NotificationPayload = {
        recipient: '+14155551234',
        subject: 'Alert',
        body: 'This is a longer message that should be truncated to 50 characters',
        channel: 'sms',
        priority: 'normal',
      };

      await custom.send(longPayload);

      const sent = custom.getSentMessages();
      expect(sent[0]?.body.length).toBe(50);
      expect(sent[0]?.body).toMatch(/\.\.\.$/);
    });

    it('should not truncate messages exactly at the limit', async () => {
      // "Subject: Body" = "Subject" (7) + ": " (2) + body
      // We need total to be exactly 160
      const bodyLength = 160 - 'Subj: '.length;
      const exactBody = 'B'.repeat(bodyLength);

      const exactPayload: NotificationPayload = {
        recipient: '+14155551234',
        subject: 'Subj',
        body: exactBody,
        channel: 'sms',
        priority: 'normal',
      };

      await adapter.send(exactPayload);

      const sent = adapter.getSentMessages();
      expect(sent[0]?.body.length).toBe(160);
      expect(sent[0]?.body).not.toMatch(/\.\.\.$/);
    });
  });

  // =========================================================================
  // Phone Number Validation Tests
  // =========================================================================

  describe('phone number validation', () => {
    it('should accept valid E.164 phone numbers', () => {
      expect(adapter.validatePhoneNumber('+14155551234')).toBe(true);
      expect(adapter.validatePhoneNumber('+442071234567')).toBe(true);
      expect(adapter.validatePhoneNumber('+8613912345678')).toBe(true);
      expect(adapter.validatePhoneNumber('+1234567')).toBe(true);
    });

    it('should reject invalid phone numbers', () => {
      expect(adapter.validatePhoneNumber('')).toBe(false);
      expect(adapter.validatePhoneNumber('not-a-phone')).toBe(false);
      expect(adapter.validatePhoneNumber('14155551234')).toBe(false); // Missing +
      expect(adapter.validatePhoneNumber('+0123456789')).toBe(false); // Starts with 0
      expect(adapter.validatePhoneNumber('+1')).toBe(false); // Too short
      expect(adapter.validatePhoneNumber('alice@example.com')).toBe(false);
    });

    it('should fail send for invalid recipient phone number', async () => {
      const payload: NotificationPayload = {
        recipient: 'not-a-phone-number',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid recipient phone number');
    });
  });

  // =========================================================================
  // Recipient Resolution Tests
  // =========================================================================

  describe('recipient resolution', () => {
    it('should resolve registered user ID to phone number', () => {
      adapter.registerRecipient('user-1', '+14155551234');
      expect(adapter.resolveRecipient('user-1')).toBe('+14155551234');
    });

    it('should return trimmed recipient for unregistered recipients', () => {
      expect(adapter.resolveRecipient('  +14155551234  ')).toBe('+14155551234');
    });

    it('should send to resolved phone number when recipient is a registered ID', async () => {
      adapter.registerRecipient('user-42', '+18005559999');

      const payload: NotificationPayload = {
        recipient: 'user-42',
        subject: 'Resolved',
        body: 'This goes to user-42',
        channel: 'sms',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.to).toBe('+18005559999');

      const sent = adapter.getSentMessages();
      expect(sent[0]?.to).toBe('+18005559999');
    });

    it('should fail send when recipient ID is not registered and is not a valid phone number', async () => {
      const payload: NotificationPayload = {
        recipient: 'user-unknown',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'normal',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid recipient phone number');
    });
  });

  // =========================================================================
  // Priority Tests
  // =========================================================================

  describe('priority handling', () => {
    it('should preserve the priority on the SMS message', async () => {
      await adapter.send({
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'high',
      });

      const sent = adapter.getSentMessages();
      expect(sent[0]?.priority).toBe('high');
    });

    it('should correctly pass each priority level', async () => {
      const priorities = ['low', 'normal', 'high', 'urgent'] as const;

      for (const priority of priorities) {
        adapter.clearSentMessages();
        await adapter.send({
          recipient: '+14155551234',
          subject: 'Test',
          body: 'Body',
          channel: 'sms',
          priority,
        });

        const sent = adapter.getSentMessages();
        expect(sent[0]?.priority).toBe(priority);
      }
    });
  });

  // =========================================================================
  // Management / Test Helpers Tests
  // =========================================================================

  describe('management', () => {
    it('should clear sent messages', async () => {
      await adapter.send({
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'normal',
      });

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return config', () => {
      const config = adapter.getConfig();
      expect(config.fromNumber).toBe('+15550000000');
      expect(config.enabled).toBe(true);
      expect(config.maxMessageLength).toBe(160);
    });

    it('should return config with custom values', () => {
      const custom = new SmsAdapter({
        fromNumber: '+18001234567',
        maxMessageLength: 320,
      });

      const config = custom.getConfig();
      expect(config.fromNumber).toBe('+18001234567');
      expect(config.maxMessageLength).toBe(320);
    });
  });

  // =========================================================================
  // Integration: Multiple sends, recipient resolution + validation + priority
  // =========================================================================

  describe('integration', () => {
    it('should combine recipient resolution with priority handling', async () => {
      adapter.registerRecipient('user-alice', '+14155550001');

      const payload: NotificationPayload = {
        recipient: 'user-alice',
        subject: 'Order Shipped',
        body: 'Your order ORD-100 has shipped!',
        channel: 'sms',
        priority: 'high',
      };

      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.to).toBe('+14155550001');

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);

      const message = sent[0]!;
      // Recipient resolved
      expect(message.to).toBe('+14155550001');
      // Message composed
      expect(message.body).toBe('Order Shipped: Your order ORD-100 has shipped!');
      // Priority preserved
      expect(message.priority).toBe('high');
      // From number from config
      expect(message.from).toBe('+15550000000');
    });

    it('should handle multiple sends independently', async () => {
      const payload1: NotificationPayload = {
        recipient: '+14155551111',
        subject: 'First',
        body: 'First body',
        channel: 'sms',
        priority: 'normal',
      };

      const payload2: NotificationPayload = {
        recipient: '+14155552222',
        subject: 'Second',
        body: 'Second body',
        channel: 'sms',
        priority: 'high',
      };

      await adapter.send(payload1);
      await adapter.send(payload2);

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.to).toBe('+14155551111');
      expect(sent[0]?.body).toBe('First: First body');
      expect(sent[1]?.to).toBe('+14155552222');
      expect(sent[1]?.body).toBe('Second: Second body');
    });

    it('should work with custom config', async () => {
      const customAdapter = new SmsAdapter({
        fromNumber: '+18009991234',
        maxMessageLength: 320,
      });

      const payload: NotificationPayload = {
        recipient: '+14155551234',
        subject: 'Welcome',
        body: 'Welcome to TaskFlow Pro! Your account has been created.',
        channel: 'sms',
        priority: 'normal',
      };

      const result = await customAdapter.send(payload);
      expect(result.success).toBe(true);

      const sent = customAdapter.getSentMessages();
      expect(sent[0]?.from).toBe('+18009991234');
      expect(sent[0]?.body).toBe('Welcome: Welcome to TaskFlow Pro! Your account has been created.');
    });

    it('should record message timestamp', async () => {
      const before = new Date();

      await adapter.send({
        recipient: '+14155551234',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'normal',
      });

      const after = new Date();
      const sent = adapter.getSentMessages();
      const messageTime = sent[0]?.timestamp;

      expect(messageTime).toBeDefined();
      expect(messageTime!.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(messageTime!.getTime()).toBeLessThanOrEqual(after.getTime());
    });
  });

  // =========================================================================
  // Adapter Interface Compliance
  // =========================================================================

  describe('adapter interface compliance', () => {
    it('should implement all required NotificationAdapter methods', () => {
      expect(typeof adapter.channel).toBe('string');
      expect(typeof adapter.send).toBe('function');
      expect(typeof adapter.isAvailable).toBe('function');
    });

    it('should never throw from send — always returns NotificationResult', async () => {
      // Even with a bad phone number, should return a result, not throw
      const result = await adapter.send({
        recipient: '',
        subject: 'Test',
        body: 'Body',
        channel: 'sms',
        priority: 'normal',
      });

      expect(result).toBeDefined();
      expect(typeof result.success).toBe('boolean');
    });
  });
});

